import{_ as i,o,c as a,a0 as p}from"./chunks/framework.SERXgfZn.js";const u=JSON.parse('{"title":"隐私政策","description":"","frontmatter":{},"headers":[],"relativePath":"privacy-policy.md","filePath":"privacy-policy.md"}'),r={name:"privacy-policy.md"};function e(t,l,n,s,h,d){return o(),a("div",null,[...l[0]||(l[0]=[p('<h1 id="隐私政策" tabindex="-1">隐私政策 <a class="header-anchor" href="#隐私政策" aria-label="Permalink to &quot;隐私政策&quot;">​</a></h1><p><strong>最后更新日期：2026年6月30日</strong></p><p>生效日期：2026年7月1日</p><p>欢迎使用 NovaAPI（以下简称“我们”或“本平台”）。我们深知数据隐私对于开发者与企业客户的极端重要性。作为一家提供全球大模型聚合路由以及特定垂类API与Agent服务的平台，我们致力于通过最高标准的安全措施保护您的信息。</p><p>本隐私保护政策旨在向您说明我们在提供产品或服务时如何收集、使用、存储、删除您的个人信息，并提示您所享有的个人信息权利。</p><p><strong>在您开始使用我们的网站和服务前，请您务必先仔细阅读和理解本隐私政策，确保您充分理解和同意之后再开始使用。</strong></p><h3 id="_1-我们收集什么信息" tabindex="-1">1. 我们收集什么信息？ <a class="header-anchor" href="#_1-我们收集什么信息" aria-label="Permalink to &quot;1\\. 我们收集什么信息？&quot;">​</a></h3><p>为了提供安全、稳定的计费与服务，我们<strong>仅收集维持服务运转的最低限度信息</strong>：</p><ul><li><p><strong>账户与结算信息</strong></p><ul><li><p><strong>基础凭证</strong>：您的注册电子邮件地址及账户密码（哈希加密加密存储）<strong>。</strong></p></li><li><p><strong>账单信息</strong>：当您进行充值时，支付处理由安全的第三方名义商家（如 Stripe, Lemon Squeezy, Paddle 等）完成。<strong>我们不直接收集或存储您的完整信用卡号等敏感金融数据。</strong></p></li></ul></li><li><p><strong>API 使用元数据 (Metadata)</strong></p><ul><li>为了实现精确的按量计费（Pay-as-you-go），我们会记录每次 API 调用的<strong>元数据</strong>：请求时间、请求 IP 地址、调用的目标模型名称（如 <code>deepseek-v4-pro</code>）、以及输入/输出的 Token 消耗量。</li></ul></li><li><p><strong>系统技术信息</strong></p><ul><li>用于安全防御及系统优化的设备信息（浏览器类型、操作系统）及报错日志。</li></ul></li></ul><h3 id="_2-我们如何使用您的信息" tabindex="-1">2. 我们如何使用您的信息？ <a class="header-anchor" href="#_2-我们如何使用您的信息" aria-label="Permalink to &quot;2\\. 我们如何使用您的信息？&quot;">​</a></h3><p>本平台收集您的个人信息，将用于以下用途。当我们要将收集到的信息用于本政策未载明的其他用途时，会事先征求您的同意和授权。</p><ol><li><p>向您提供、维护、改进产品或服务；</p></li><li><p>向您发送关于系统安全、产品或服务变化等方面的重要通知；</p></li><li><p>激活或验证产品或服务；</p></li><li><p>在法律法规允许的前提下向您推广、介绍产品；您有权选择退出；</p></li><li><p>为您提供个性化产品、服务或个性化用户体验；</p></li><li><p>开展内部审计、数据分析和研究，以改善我们的产品和服务；您在自动化个人决策和用户画像方面的权利；</p></li><li><p>保护我们产品、服务和用户的信息技术安全；</p></li><li><p>遵从和执行适用的法律要求或相关的行业标准，如法律有关于实名认证的规定，所收集的包括银行卡号在内的信息都只用于实名认证用途，而不会用于其他目的；</p></li><li><p>经您许可的其他用途。如您对数据处理用途有疑义，或希望我们停止其中一种或多种数据使用方式，请与客服团队联系。</p></li></ol><h3 id="_3-我们如何共享信息" tabindex="-1">3. 我们如何共享信息？ <a class="header-anchor" href="#_3-我们如何共享信息" aria-label="Permalink to &quot;3\\. 我们如何共享信息？&quot;">​</a></h3><p>我们<strong>绝不出售、出租</strong>您的任何个人数据。我们仅在以下必要场景下与受信任的第三方共享信息：</p><ul><li><p>**模型供应商：接收完成推理所需的用户内容及技术信息。**他们将根据其各自的隐私政策处理数据。</p></li><li><p><strong>云与基础设施供应商</strong>：提供服务器、数据库、对象存储、CDN、DDoS 防护、监控、日志、邮件和客户支持。它们受严格的数据处理协议（DPA）约束。</p></li><li><p><strong>政府、监管和执法机构</strong>：仅在有合法依据、具备适当权限且请求范围合理时披露；在法律允许时，我们会审查、缩小或质疑过度请求。</p></li></ul><h3 id="_4-数据安全与存储" tabindex="-1">4. 数据安全与存储 <a class="header-anchor" href="#_4-数据安全与存储" aria-label="Permalink to &quot;4\\. 数据安全与存储&quot;">​</a></h3><ul><li><p><strong>传输加密</strong>：所有通过 NovaAPI 进出的流量均通过强标准的 TLS/SSL 端到端加密（HTTPS）。</p></li><li><p><strong>密钥脱敏</strong>：您生成的 <code>sk-</code> API Key 及上游渠道密钥在数据库中均采用行业最高标准的非对称加密存储。</p></li><li><p><strong>没有绝对的安全</strong>：尽管我们采用了顶级的商业防护措施，但互联网传输无法保证 100% 绝对安全。请您务必妥善保管自己的 API Key，避免在公开代码仓库中硬编码泄露。</p></li></ul><h3 id="_5-数据保留期限" tabindex="-1">5. 数据保留期限 <a class="header-anchor" href="#_5-数据保留期限" aria-label="Permalink to &quot;5\\. 数据保留期限&quot;">​</a></h3><ul><li><p><strong>账户数据</strong>：只要您的账户处于活跃状态，我们将一直保留您的注册信息。</p></li><li><p><strong>日志数据</strong>：为处理账单争议及异常调用分析，API 调用的元数据（仅限时间、模型、Token数）<strong>最多保留 90 天</strong>，随后将自动滚动删除或完全匿名化。</p></li><li><p><strong>注销清除</strong>：当您主动申请注销账户后，我们将在 30 日内从活动数据库中永久抹除您的个人标识信息。</p></li></ul><h3 id="_6-您的权利" tabindex="-1">6. 您的权利 <a class="header-anchor" href="#_6-您的权利" aria-label="Permalink to &quot;6\\. 您的权利&quot;">​</a></h3><p>依据您所在地法律及我们所扮演的角色，您可能有权：</p><ul><li><p>知情、访问并获取个人信息副本；</p></li><li><p>更正或补充不准确的信息；</p></li><li><p>删除个人信息或注销账户；</p></li><li><p>限制或反对特定处理；</p></li><li><p>撤回同意；</p></li><li><p>获取结构化、常用且机器可读的数据，或请求转移；</p></li><li><p>了解自动化决策的基本情况，并在法律规定时拒绝仅由自动化决策作出的重大决定；</p></li><li><p>退订营销信息；</p></li><li><p>就隐私处理提出投诉、申诉或向监管机构投诉。</p></li></ul><p>如需行使上述权利，请通过本政策末尾的联系方式与我们联系。</p><h3 id="_7-cookie-与类似技术" tabindex="-1">7. Cookie 与类似技术 <a class="header-anchor" href="#_7-cookie-与类似技术" aria-label="Permalink to &quot;7\\. Cookie 与类似技术&quot;">​</a></h3><p>我们可能使用：</p><ul><li><p>登录与会话 Cookie，用于保持登录状态和安全退出；</p></li><li><p>安全 Cookie，用于防机器人、DDoS、欺诈和异常登录；</p></li><li><p>偏好 Cookie，用于记住语言和界面设置；</p></li><li><p>分析 Cookie，用于了解网站性能和使用情况，但仅在适用法律允许或您同意后启用。</p></li></ul><p>我们不以出售个人信息为目的使用 Cookie，并支持用户管理非必要 Cookie。</p><h3 id="_8-跨境数据传输" tabindex="-1">8. 跨境数据传输 <a class="header-anchor" href="#_8-跨境数据传输" aria-label="Permalink to &quot;8\\. 跨境数据传输&quot;">​</a></h3><p>您的信息可能被传输至您所在国家或地区以外的服务器进行处理。在此情况下，我们会采取适当措施确保您的信息得到与本隐私政策一致的保护。我们将在符合适用法律要求的前提下进行跨境数据传输。</p><h3 id="_9-政策的更新" tabindex="-1">9. 政策的更新 <a class="header-anchor" href="#_9-政策的更新" aria-label="Permalink to &quot;9\\. 政策的更新&quot;">​</a></h3><p>我们可能因服务、供应商、技术或法律变化更新本政策。重大变更将通过电子邮件、控制台或网站提前合理通知；法律要求时会重新取得同意。页面顶部将显示最新更新和生效日期。继续使用 NovaAPI，即表明您接受更新后的隐私条款。</p><h3 id="_10-联系我们" tabindex="-1">10. 联系我们 <a class="header-anchor" href="#_10-联系我们" aria-label="Permalink to &quot;10\\. 联系我们&quot;">​</a></h3><p>果您对本隐私政策有任何疑问、意见或请求，请通过以下方式联系我们：</p><p>电子邮箱：support@novaapis.com</p><p>我们将在收到请求后 15 个工作日内予以答复。</p>',35)])])}const g=i(r,[["render",e]]);export{u as __pageData,g as default};
